  const dur = reverse ? "42s" : "34s";
  return (
    <div className={`overflow-hidden py-3 border-y ${dark ? "bg-black border-white/[0.08]" : "bg-white dark:bg-gray-950 border-black/[0.07] dark:border-white/[0.07]"}`}>
