// ─── Single Seamless Review Track ────────────────────────────────────────────
function ReviewTrack({ reviews }: { reviews: any[] }) {
  // Triple the set so the loop is always full and resets invisibly
  const items = [...reviews, ...reviews, ...reviews];
  // Speed: ~45s per full set width
  const dur = `${Math.max(reviews.length * 3.5, 40)}s`;
  return (
    <div className="flex overflow-hidden" style={{ maskImage: "linear-gradient(to right, transparent, black 8%, black 92%, transparent)" }}>
      <div
        className="flex shrink-0"
        style={{
          animation: `marquee-left ${dur} linear infinite`,
          willChange: "transform",
        }}
      >
        {items.map((r, i) => <ReviewCard key={`${r.id}-${i}`} r={r} />)}
      </div>
    </div>
  );
}

